function filterTable() {
  const dropdown = document.getElementById("regionDropdown");
  const filterValue = dropdown.value.toLowerCase();
  const table = document.getElementById("regionTable");
  const rows = table.getElementsByTagName("tr");

  // Loop through all table rows (starting from index 1 to skip the header)
  for (let i = 1; i < rows.length; i++) {
    // Assume the 'Region' data is in the second column (index 1)
    const regionCell = rows[i].getElementsByTagName("td")[1];

    if (regionCell) {
      const regionText = regionCell.textContent || regionCell.innerText;

      // If 'all' is selected or the cell text matches the filter, show row; otherwise hide it
      if (filterValue === "all" || regionText.toLowerCase() === filterValue) {
        rows[i].style.display = "";
      } else {
        rows[i].style.display = "none";
      }
    }
  }
