import React, { useState, useMemo } from 'react';

const INITIAL_DATA = [
  { id: 'CLM001', customer: 'John Doe', product: 'Laptop X1', date: '2023-10-01', status: 'Approved', amount: 1200 },
  { id: 'CLM002', customer: 'Jane Smith', product: 'Phone 15', date: '2023-10-05', status: 'Pending', amount: 800 },
  { id: 'CLM003', customer: 'Bob Johnson', product: 'Monitor 4K', date: '2023-09-28', status: 'Rejected', amount: 300 },
  { id: 'CLM004', customer: 'Alice Brown', product: 'Tablet Pro', date: '2023-10-12', status: 'Approved', amount: 500 },
  { id: 'CLM005', customer: 'Charlie Davis', product: 'Laptop X1', date: '2023-10-15', status: 'Pending', amount: 1200 },
];

const WarrantyClaimsTable = () => {
  const [claims] = useState(INITIAL_DATA);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [sortConfig, setSortConfig] = useState({ key: 'date', direction: 'desc' });

  // Handle Filtering and Sorting
  const processedClaims = useMemo(() => {
    let filtered = claims.filter((claim) => {
      const matchesSearch = 
        claim.customer.toLowerCase().includes(searchTerm.toLowerCase()) ||
        claim.product.toLowerCase().includes(searchTerm.toLowerCase()) ||
        claim.id.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesStatus = statusFilter === 'All' || claim.status === statusFilter;

      return matchesSearch && matchesStatus;
    });

    if (sortConfig.key) {
      filtered.sort((a, b) => {
        if (a[sortConfig.key] < b[sortConfig.key]) {
          return sortConfig.direction === 'asc' ? -1 : 1;
        }
        if (a[sortConfig.key] > b[sortConfig.key]) {
          return sortConfig.direction === 'asc' ? 1 : -1;
        }
        return 0;
      });
    }

    return filtered;
  }, [claims, searchTerm, statusFilter, sortConfig]);

  const requestSort = (key) => {
    let direction = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'sans-serif' }}>
      <h2>Warranty Claims</h2>

      {/* Filters */}
      <div style={{ marginBottom: '20px', display: 'flex', gap: '10px' }}>
        <input
          type="text"
          placeholder="Search by ID, customer, or product..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          style={{ padding: '8px', width: '300px' }}
        />

        <select 
          value={statusFilter} 
          onChange={(e) => setStatusFilter(e.target.value)}
          style={{ padding: '8px' }}
        >
          <option value="All">All Statuses</option>
          <option value="Approved">Approved</option>
          <option value="Pending">Pending</option>
          <option value="Rejected">Rejected</option>
        </select>
      </div>

      {/* Table */}
      <table border="1" cellPadding="10" style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
        <thead>
          <tr style={{ backgroundColor: '#f4f4f4' }}>
            <th onClick={() => requestSort('id')} style={{ cursor: 'pointer' }}>Claim ID ▲▼</th>
            <th onClick={() => requestSort('customer')} style={{ cursor: 'pointer' }}>Customer ▲▼</th>
            <th onClick={() => requestSort('product')} style={{ cursor: 'pointer' }}>Product ▲▼</th>
            <th onClick={() => requestSort('date')} style={{ cursor: 'pointer' }}>Date Filed ▲▼</th>
            <th onClick={() => requestSort('status')} style={{ cursor: 'pointer' }}>Status ▲▼</th>
            <th onClick={() => requestSort('amount')} style={{ cursor: 'pointer' }}>Amount ($) ▲▼</th>
          </tr>
        </thead>
        <tbody>
          {processedClaims.length > 0 ? (
            processedClaims.map((claim) => (
              <tr key={claim.id}>
                <td>{claim.id}</td>
                <td>{claim.customer}</td>
                <td>{claim.product}</td>
                <td>{claim.date}</td>
                <td style={{ color: claim.status === 'Rejected' ? 'red' : claim.status === 'Approved' ? 'green' : 'orange' }}>
                  {claim.status}
                </td>
                <td>{claim.amount.toFixed(2)}</td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="6" style={{ textAlign: 'center' }}>No claims found.</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default WarrantyClaimsTable;

