class RecursiveSwitcher:
    def __init__(self, data):
        self.nodes = {item['id']: item for item in data}

    def get_value(self, node_id):
        node = self.nodes.get(node_id)
        if not node: return None
        # Recursive resolution: use own value if exists, else check parent
        if node['value'] is not None:
            return node['value']
        if node['parent_id'] is not None:
            return self.get_value(node['parent_id'])
        return None

