# Instead of multiple round-trips to the DB, resolve the hierarchy in one query.
GET_RESOLVED_VALUE_SQL = """
WITH RECURSIVE switch_path AS (
    -- Anchor member: start with the target node
    SELECT id, parent_id, value, 1 as depth
    FROM switches WHERE id = %s
    UNION ALL
    -- Recursive member: move up to parents
    SELECT s.id, s.parent_id, s.value, sp.depth + 1
    FROM switches s
    INNER JOIN switch_path sp ON s.id = sp.parent_id
    WHERE sp.value IS NULL -- Stop recursion once a value is found
)
SELECT value FROM switch_path WHERE value IS NOT NULL ORDER BY depth ASC LIMIT 1;
"""

