import functools

class CachedSwitcher(RecursiveSwitcher):
    def __init__(self, data, redis_client=None):
        super().__init__(data)
        self.redis = redis_client

    @functools.lru_cache(maxsize=1024)
    def get_value_optimized(self, node_id):
        # In a real scenario, check Redis first, then fallback to DB/Logic
        return self.get_value(node_id)

